#include<bits/stdc++.h>
#define it iterator
using namespace std;
long long n,q,offset;
struct node
{
    mutable long long l,r,v;
    node(long long l=0,long long r=0,long long v=0):l(l),r(r),v(v){}
    bool operator<(const node&b)const
    {
        return l<b.l;
    }
};
set<node> odt,tmp;
set<node>::it split(long long pos)
{
    set<node>::it i=odt.lower_bound(node(pos));
    if(i!=odt.end()&&i->l==pos)
    {
        return i;
    }
    if((--i)->r<pos)
    {
        return odt.end();
    }
    long long l=i->l,r=i->r,v=i->v;
    odt.erase(i);
    odt.insert(node(l,pos-1,v));
    return odt.insert(node(pos,r,v)).first;
}
void assign(long long l,long long r,long long v)
{
    set<node>::it itr=split(r+1),itl=split(l);
    odt.erase(itl,itr);
    odt.insert(node(l,r,v));
}
void exchange(long long x,long long y)
{
    if(x>y)
    {
        swap(x,y);
    }
    split(y+1);
    split(x+1);
    set<node>::it itr=split(y),itl=split(x);
    swap(itl->v,itr->v);
}
long long mov(long long x)
{
    return (x-1+offset)%n+1;
}
long long bck(long long x)
{
    return (x-1-offset+n)%n+1;
}
long long rev(long long i)
{
    return (i==1?1:(n-i+2));
}
void flip()
{
    tmp.clear();
    for(set<node>::it i=odt.begin();i!=odt.end();i++)
    {
        long long l=rev(mov(i->r)),r=rev(mov(i->l));
        if(l<=r)
        {
            tmp.insert(node(l,r,i->v));
        }
        else
        {
            tmp.insert(node(l,n,i->v));
            tmp.insert(node(1,r,i->v));
        }
    }
    odt=tmp;
    offset=0;
}
long long cntr()
{
    long long s=0,v=0;
    for(set<node>::it i=odt.begin();i!=odt.end();i++)
    {
        if(i->v!=v)
        {
            s++;
            v=i->v;
        }
    }
    return max(s-(odt.begin()->v==v),1ll);
}
long long cnt1(long long l,long long r)
{
    long long s=0,v=0;
    set<node>::it itr=split(r+1),itl=split(l);
    while(itl!=itr)
    {
        if(itl->v!=v)
        {
            s++;
            v=itl->v;
        }
        itl++;
    }
    return s;
}
long long cnt2(long long l,long long r)
{
    long long s=0,v=0;
    set<node>::it itl=split(l);
    while(itl!=odt.end())
    {
        if(itl->v!=v)
        {
            s++;
            v=itl->v;
        }
        itl++;
    }
    set<node>::it itr=split(r+1);
    itl=odt.begin();
    while(itl!=itr)
    {
        if(itl->v!=v)
        {
            s++;
            v=itl->v;
        }
        itl++;
    }
    return s;
}
int main()
{
    long long c;
    scanf("%lld%lld",&n,&c);
    for(long long i=1;i<=n;i++)
    {
        long long x;
        scanf("%lld",&x);
        odt.insert(node(i,i,x));
    }
    scanf("%lld",&q);
    while(q--)
    {
        string op;
        long long l,r,k;
        cin>>op;
        if(op=="R")
        {
            scanf("%lld",&k);
            offset=(offset+k)%n;
        }
        else if(op=="F")
        {
            flip();
        }
        else if(op=="S")
        {
            scanf("%lld%lld",&l,&r);
            l=bck(l);
            r=bck(r);
            exchange(l,r);
        }
        else if(op=="P")
        {
            scanf("%lld%lld%lld",&l,&r,&k);
            l=bck(l);
            r=bck(r);
            if(l<=r)
            {
                assign(l,r,k);
            }
            else
            {
                assign(l,n,k);
                assign(1,r,k);
            }
        }
        else if(op=="C")
        {
            printf("%lld\n",cntr());
        }
        else
        {
            scanf("%lld%lld",&l,&r);
            l=bck(l);
            r=bck(r);
            if(l<=r)
            {
                printf("%lld\n",cnt1(l,r));
            }
            else
            {
                printf("%lld\n",cnt2(l,r));
            }
        }
    }
    return 0;
}
